insert into public.products (id, category_id, brand_id, name, slug, description, long_description, sku, price, sale_price, discount, rating, reviews_count, inventory, options, status) values
('p0000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000003', 'Sony WH-1000XM5 ANC Headphones', 'sony-wh-1000xm5-headphones', 'Premium wireless noise-cancelling overhead headphones.', 'Immerse yourself in high-fidelity audio with Sony industry-leading active noise cancelling (ANC) processor. Includes smart listening, wearing sensors, and up to 30 hours of battery life.', 'SONY-WH-XM5', 450000.00, 399000.00, 11.33, 4.85, 234, 45, '[{"name": "Color", "values": ["Black", "Silver", "Midnight Blue"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000002', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000003', 'Sony HT-A7000 Dolby Atmos Soundbar', 'sony-ht-a7000-soundbar', 'Masterclass home theatre soundbar with 7.1.2 virtual surround channels.', 'Experience cinema-quality acoustics inside your home. Integrated dual subwoofers and up-firing drivers create realistic surround effects.', 'SONY-HT-A7000', 1350000.00, 1250000.00, 7.41, 4.72, 89, 15, '[{"name": "Bundle", "values": ["Standard", "With Subwoofer", "Full Home Theater"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000003', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Apple HomePod 2nd Gen Speaker', 'apple-homepod-2-speaker', 'Acoustic power meets intelligent Siri smart-home control.', 'Rich, deep bass and crystal-clear highs fine-tuned by a powerful computational audio model. Seamlessly interacts with your Apple devices.', 'APL-HOMEPOD2', 380000.00, 350000.00, 7.89, 4.65, 120, 30, '[{"name": "Color", "values": ["White", "Midnight"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000004', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000003', 'Sony BRAVIA XR 65-Inch OLED TV', 'sony-bravia-xr-65-oled-tv', 'Ultimate contrast OLED TV powered by Cognitive Processor XR.', 'Vibrant real-life colors and deep perfect blacks. Seamlessly optimized for next-gen gaming consoles and streaming cinema apps.', 'SONY-BRV-OLED65', 2800000.00, 2650000.00, 5.36, 4.91, 54, 10, '[{"name": "Warranty", "values": ["1 Year", "2 Year", "3 Year"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000005', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Apple TV 4K 128GB Wi-Fi + Ethernet', 'apple-tv-4k-128gb-ethernet', 'High-end dynamic streaming box with Apple A15 Bionic chip.', 'Transforms any television into an intelligent cinematic smart hub. Enjoy true HDR10+ visuals and Dolby Atmos spatial audio configurations.', 'APL-TV4K-128', 190000.00, 185000.00, 2.63, 4.88, 432, 70, '[{"name": "Storage", "values": ["64GB", "128GB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000006', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000010', 'Dell Professional Soundbar Speaker', 'dell-professional-soundbar-sb521a', 'Sleek, magnetic mount audio accessory for Dell premium monitors.', 'Compact acoustic soundbar that snaps onto your office screen. Perfect for high-quality video calling and space-conscious workstations.', 'DELL-SB-521A', 75000.00, 68000.00, 9.33, 4.41, 142, 60, '[{"name": "Bundle", "values": ["Standard", "With USB Hub"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000007', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000007', 'Dyson Pure Cool Tower Fan AM07', 'dyson-pure-cool-am07-fan', 'Air multiplier bladeless tower fan with remote control.', 'Produces high-velocity, powerful cooling currents without safety hazards or difficult-to-clean grills. Whispering quiet motor.', 'DYSON-AM07-FAN', 520000.00, 499000.00, 4.04, 4.60, 95, 25, '[{"name": "Color", "values": ["Iron/Blue", "White/Silver"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000008', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000003', 'Sony Alpha 7R V Full Frame Mirrorless Camera', 'sony-alpha-7rv-mirrorless-camera', '61.0 Megapixels of pure optic detailing powered by AI processing.', 'Next-generation intelligent auto-focusing for tracking people, cars, and insects. Exceptional 8K resolution video stabilization.', 'SONY-ILCE-7RM5', 4600000.00, 4300000.00, 6.52, 4.96, 42, 8, '[{"name": "Bundle", "values": ["Body Only", "With 24-70mm GM II", "With 50mm f/1.2 GM"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000009', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Apple Watch Ultra 2 Titanium LTE', 'apple-watch-ultra-2-titanium', 'The ultimate, rugged sports wearable carved in aerospace titanium.', 'Featuring the brightest always-on retina display, dual-frequency high-precision GPS positioning, and up to 72 hours of low power longevity.', 'APL-WATCH-ULT2', 1250000.00, 1150000.00, 8.00, 4.89, 156, 35, '[{"name": "Color", "values": ["Ocean Blue Band", "Orange Alpine Loop", "Black Trail Loop"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000010', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000003', 'Sony PlayStation VR2 Headset', 'sony-playstation-vr2-headset', 'Stunning 4K HDR virtual reality headset for PlayStation 5.', 'Intelligent eye tracking, advanced physical headset feedback vibration, and high-precision immersive controllers. Dive into digital fantasy.', 'SONY-PS-VR2', 980000.00, 890000.00, 9.18, 4.75, 78, 18, '[{"name": "Bundle", "values": ["Standard VR2", "Horizon Call of Mountain Bundle"]}]'::jsonb, 'active');
insert into public.products (id, category_id, brand_id, name, slug, description, long_description, sku, price, sale_price, discount, rating, reviews_count, inventory, options, status) values
('p0000000-0000-0000-0000-000000000011', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'Apple iPhone 16 Pro Max', 'apple-iphone-16-pro-max', 'Flagship titanium phone powered by Apple intelligence and A18 Pro chip.', 'Premium grade aerospace titanium casing with a larger 6.9-inch display, physical Camera Control capture switch, and 5x optical telephoto lens.', 'APL-IPH16PM', 2400000.00, 2250000.00, 6.25, 4.92, 612, 100, '[{"name": "Color", "values": ["Desert Titanium", "Natural Titanium", "White Titanium", "Black Titanium"]}, {"name": "Storage", "values": ["256GB", "512GB", "1TB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000012', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy S25 Ultra 5G', 'samsung-galaxy-s25-ultra', 'Ultimate flagship smartphone with Snapdragon 8 Gen 4 and S-Pen.', 'Corning Gorilla Armor anti-reflective glass, massive 200MP expert camera grid, and full-array local galaxy AI capabilities.', 'SAM-S25ULT', 2300000.00, 2150000.00, 6.52, 4.88, 489, 90, '[{"name": "Color", "values": ["Titanium Gray", "Titanium Black", "Titanium Violet"]}, {"name": "Storage", "values": ["256GB", "512GB", "1TB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000013', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy Z Fold 6 5G', 'samsung-galaxy-z-fold6', 'Beautiful folding tablet hybrid phone with dual AMOLED dynamic displays.', 'Slimmer, lighter, and armor aluminum protected folding device. Run up to three background work screens simultaneously.', 'SAM-FOLD6', 2600000.00, 2450000.00, 5.77, 4.67, 85, 20, '[{"name": "Color", "values": ["Silver Shadow", "Navy Blue", "Pink Gold"]}, {"name": "Storage", "values": ["256GB", "512GB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000014', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'Apple iPhone 16 Plus', 'apple-iphone-16-plus', '6.7-inch energetic model with advanced A18 chip and dynamic island.', 'Beautifully saturated color-infused rear glass. High-speed action customizable button and a highly robust thermal control architecture.', 'APL-IPH16PLS', 1750000.00, 1650000.00, 5.71, 4.70, 241, 80, '[{"name": "Color", "values": ["Teal Green", "Ultramarine Blue", "Pink", "Black"]}, {"name": "Storage", "values": ["128GB", "256GB", "512GB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000015', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy A55 5G', 'samsung-galaxy-a55', 'Premium mid-range phone with elegant glass back and metal frame.', 'Stunning 6.6-inch Super AMOLED 120Hz display with Knox Vault data safety security. High-speed octa-core processor.', 'SAM-A55-5G', 540000.00, 499000.00, 7.59, 4.54, 382, 110, '[{"name": "Color", "values": ["Awesome Navy", "Awesome Iceblue", "Awesome Lilac"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000016', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000003', 'Sony Xperia 1 VI 5G Pro', 'sony-xperia-1vi-5g', 'Optic specialist phone with variable telephoto continuous optical zoom.', 'Perfect 19.5:9 display with professional screen colors tuned by CineAlta. Real-time eye auto-focus tracking.', 'SONY-XP1-VI', 1600000.00, 1490000.00, 6.88, 4.78, 59, 15, '[{"name": "Color", "values": ["Khaki Green", "Platinum Silver", "Black"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000017', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'Apple iPhone 15 Pro Max (Refurbished)', 'apple-iphone-15-pro-max-refurbished', 'Certified pre-owned 15 Pro Max in excellent aesthetic condition.', 'Features titanium frame, A17 Pro high-performance gaming chip, and versatile custom USB-C port interface. Fully verified health metrics.', 'APL-IPH15PM-RF', 1650000.00, 1550000.00, 6.06, 4.62, 148, 25, '[{"name": "Color", "values": ["Natural Titanium", "Blue Titanium"]}, {"name": "Storage", "values": ["256GB", "512GB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000018', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy S24 Ultra 5G', 'samsung-galaxy-s24-ultra', 'AI pioneering smartphone with 200MP camera and robust build.', 'Features Snapdragon 8 Gen 3 for Galaxy, titanium borders, and seven generations of guaranteed operating system security updates.', 'SAM-S24ULT', 1850000.00, 1750000.00, 5.41, 4.83, 734, 40, '[{"name": "Color", "values": ["Titanium Yellow", "Titanium Gray", "Titanium Black"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000019', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'Apple iPhone 16 Base Model', 'apple-iphone-16-base', 'Standard 6.1-inch A18 powerhouse with dual ultra-wide cameras.', 'High-performance camera control interface, spatial capturing, dynamic island dashboard, and beautiful light-scattering rear glass finish.', 'APL-IPH16', 1450000.00, 1380000.00, 4.83, 4.74, 189, 75, '[{"name": "Color", "values": ["Pink", "Ultramarine Blue", "White", "Black"]}, {"name": "Storage", "values": ["128GB", "256GB"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000020', 'c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy Z Flip 6 5G', 'samsung-galaxy-z-flip6', 'Pocket-sized folding luxury fashion statement smartphone.', 'A 50MP dynamic camera with flexible FlexCam auto-zoom tripod utility. Sizable dynamic folder window customizable external display.', 'SAM-FLIP6', 1480000.00, 1380000.00, 6.76, 4.60, 92, 35, '[{"name": "Color", "values": ["Mint Green", "Blue Shadow", "Yellow Accent"]}]'::jsonb, 'active');
insert into public.products (id, category_id, brand_id, name, slug, description, long_description, sku, price, sale_price, discount, rating, reviews_count, inventory, options, status) values
('p0000000-0000-0000-0000-000000000021', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000001', 'Apple MacBook Pro 16-Inch M4 Max', 'apple-macbook-pro-16-m4-max', 'Extreme computer processing unit with M4 Max chip, 48GB Unified Memory.', 'Stunning 16-inch Liquid Retina XDR screen with up to 24 hours of massive battery performance. Best-in-class multi-threaded computation.', 'APL-MBP16-M4M', 4800000.00, 4600000.00, 4.17, 4.97, 72, 12, '[{"name": "Storage", "values": ["1TB SSD", "2TB SSD"]}, {"name": "Warranty", "values": ["1 Year", "3 Year AppleCare+"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000022', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell XPS 15 9530 Creator Laptop', 'dell-xps-15-9530', 'OLED touchscreen designer workspace with NVIDIA RTX 4060 graphics.', 'Machined aluminum chassis, carbon fiber palm rests, and stunning 3.5K infinite edge display. Incredible acoustics output.', 'DELL-XPS15-9530', 2700000.00, 2550000.00, 5.56, 4.75, 94, 20, '[{"name": "Storage", "values": ["512GB SSD", "1TB SSD"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000023', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell Inspiron 16 Plus', 'dell-inspiron-16-plus', 'Spacious 16-inch workhorse powered by Intel Core Ultra 7 CPU.', 'Equipped with visual comforts, smart AI video conference tools, and dynamic graphics array. Ideal balance of performance and cost.', 'DELL-INS16-PLS', 1350000.00, 1280000.00, 5.19, 4.50, 112, 45, '[{"name": "Color", "values": ["Platinum Silver", "Carbon Black"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000024', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell Alienware m18 Gaming Laptop', 'dell-alienware-m18', 'Monstrous desktop replacement notebook with Intel i9 and RTX 4090.', 'Massive mechanical keyboard integration, dynamic cryogenic cooling chambers, and crystal-clear 480Hz motion refreshing display.', 'DELL-AW-M18', 4950000.00, 4750000.00, 4.04, 4.88, 34, 6, '[{"name": "Bundle", "values": ["Standard Pack", "Ultimate Gaming Bundle (Mouse + Headset)"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000025', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000001', 'Apple MacBook Air 13-Inch M3', 'apple-macbook-air-13-m3', 'Incredibly lightweight, silent powerhouse with advanced M3 processor.', 'Completely fanless thermal design, liquid retina display, and up to 18 hours of portable usage. Sleek unibody profile.', 'APL-MBA13-M3', 1450000.00, 1380000.00, 4.83, 4.85, 342, 60, '[{"name": "Color", "values": ["Midnight", "Starlight", "Space Gray", "Silver"]}, {"name": "Storage", "values": ["256GB SSD", "512GB SSD"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000026', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell Latitude 7440 Business Laptop', 'dell-latitude-7440', 'Enterprise grade secure laptop with high-speed 5G module compatibility.', 'Lightweight magnesium casing, integrated physical privacy shutter webcam, and corporate IT grade data protection systems.', 'DELL-LAT7440', 1650000.00, 1550000.00, 6.06, 4.45, 87, 30, '[{"name": "Warranty", "values": ["1 Year Basic", "3 Year ProSupport Plus"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000027', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell G15 5530 Gaming Laptop', 'dell-g15-5530', 'Value oriented entry-level gaming machine with RTX 4050.', 'Features retro orange-backlit keyboards, high-pressure cooling fans, and fast 165Hz FHD display panels. Highly moddable.', 'DELL-G15-4050', 1150000.00, 1080000.00, 6.09, 4.38, 143, 40, '[{"name": "Color", "values": ["Dark Shadow Gray", "Quantum White"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000028', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000002', 'Samsung Galaxy Book4 Ultra', 'samsung-galaxy-book4-ultra', 'Intelligent luxury laptop with Intel Core Ultra 9 and Dynamic AMOLED 2X.', 'Extreme integration within the Samsung Galaxy tablet/phone ecosystem. Super-slim design with tactile glass cursor pad.', 'SAM-GB4-ULT', 2900000.00, 2750000.00, 5.17, 4.80, 45, 10, '[{"name": "Storage", "values": ["1TB SSD", "2TB SSD"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000029', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Apple MacBook Pro 14-Inch M4', 'apple-macbook-pro-14-m4', 'Professional portable work unit with Apple M4 standard processor.', 'Features beautiful high-fidelity micro-LED display, up to three external screen capabilities, and liquid spatial audio arrays.', 'APL-MBP14-M4', 2150000.00, 1999000.00, 7.02, 4.88, 178, 50, '[{"name": "Color", "values": ["Space Black", "Silver"]}, {"name": "Storage", "values": ["512GB SSD", "1TB SSD"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000030', 'c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000010', 'Dell XPS 13 9340 Ultrabook', 'dell-xps-13-9340', 'Sleek, seamless glass trackpad layout with Intel Core Ultra 5.', 'The ultimate visual travel companion. Features edge-to-edge keyboard layout, high-frequency brightness, and magnesium finish.', 'DELL-XPS13-9340', 1680000.00, 1580000.00, 5.95, 4.56, 90, 22, '[{"name": "Color", "values": ["Graphite Gray", "Silver Sparkle"]}]'::jsonb, 'active');
insert into public.products (id, category_id, brand_id, name, slug, description, long_description, sku, price, sale_price, discount, rating, reviews_count, inventory, options, status) values
('p0000000-0000-0000-0000-000000000031', 'c0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000006', 'Luxury Silk Evening Gown', 'luxury-silk-evening-gown', 'Pure Mulberry silk floor-length designer evening gown.', 'Artisan woven double-lined silk with elegant draping features and delicate gold trim embroidery. Feels incredibly soft against skin.', 'FASH-SLK-GWN', 320000.00, 290000.00, 9.38, 4.88, 34, 18, '[{"name": "Size", "values": ["XS", "S", "M", "L", "XL"]}, {"name": "Color", "values": ["Royal Blue", "Emerald Green", "Classic Black"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000032', 'c0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000004', 'Nike Windrunner Hooded Jacket', 'nike-windrunner-jacket', 'Iconic V-shaped chevron training windbreaker jacket.', 'Water-repellent, lightweight recycled fabric weave. Features mesh vents for complete body breathability during runs or leisure.', 'NIKE-WND-JKT', 85000.00, 78000.00, 8.24, 4.62, 198, 80, '[{"name": "Size", "values": ["S", "M", "L", "XL"]}, {"name": "Color", "values": ["Red/White", "All Black", "Grey/Navy"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000033', 'c0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000001', 'Apple Heritage Graphic Tee', 'apple-heritage-graphic-tee', 'Heavyweight organic cotton vintage computing graphic shirt.', 'Features the retro multicolor Apple stripe logo. Premium high-density collar structure that maintains its shape after extensive washing.', 'APL-HRT-TEE', 45000.00, 42000.00, 6.67, 4.79, 312, 150, '[{"name": "Size", "values": ["S", "M", "L", "XL", "XXL"]}, {"name": "Color", "values": ["Vintage White", "Heather Grey"]}]'::jsonb, 'active'),
