('p0000000-0000-0000-0000-000000000079', 'c0000000-0000-0000-0000-000000000008', 'b0000000-0000-0000-0000-000000000008', 'IKEA BESTÅ Premium TV Media Console', 'ikea-besta-tv-console', 'Glass top, clean push-open drawer TV entertainment board.', 'Clean integrated cable channels routing complex wires hidden beneath modern glass top protectors.', 'IKEA-BST-TV', 195000.00, 180000.00, 7.69, 4.60, 85, 20, '[{"name": "Color", "values": ["Walnut Effect/Dark Glass", "White Gloss/Clear Glass"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000080', 'c0000000-0000-0000-0000-000000000008', 'b0000000-0000-0000-0000-000000000008', 'IKEA KALLAX Shelving Unit 4x4', 'ikea-kallax-shelving-unit', 'Modular cube storage organizer display square bookshelf.', 'A versatile layout that can stand tall or lie sideways on walls. Insert custom fabric storage drawers inside cubes.', 'IKEA-KLX-4X4', 88000.00, 79000.00, 10.23, 4.72, 498, 55, '[{"name": "Color", "values": ["Classic White", "Black Wood Effect"]}]'::jsonb, 'active');
insert into public.products (id, category_id, brand_id, name, slug, description, long_description, sku, price, sale_price, discount, rating, reviews_count, inventory, options, status) values
('p0000000-0000-0000-0000-000000000081', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000008', 'IKEA VÄRDERA Ceramic Dinnerware (18-Piece)', 'ikea-vardera-dinnerware-set', 'Premium break-resistant square-edge porcelain dinner set.', 'Elegant, high-durability glazed feldspar porcelain plates. Microwave and dishwasher safe. Includes soup bowls, side and main plates.', 'IKEA-VRD-DIN', 48000.00, 42000.00, 12.50, 4.65, 114, 85, '[{"name": "Color", "values": ["Classic Off-White"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000082', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000007', 'Dyson Airblade Tap Water Filter', 'dyson-airblade-water-filter', 'Dynamic UV sterilizing water filtering smart faucet system.', 'High-performance cellular filtration removes heavy metals and 99.9% of bacteria instantly. Touchless infrared sensor release.', 'DYSON-AB-TAP', 320000.00, 290000.00, 9.38, 4.70, 32, 10, '[{"name": "Bundle", "values": ["Standard Faucet Tap"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000083', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000002', 'Samsung Family Hub Smart Fridge', 'samsung-family-hub-smart-fridge', '650L double door intelligent refrigerator with touch display.', 'Features dynamic triple cooling zones. Integrated internal cameras track stock expiry date alerts synced directly to your phone.', 'SAM-HUB-FRG', 3800000.00, 3600000.00, 5.26, 4.90, 14, 5, '[{"name": "Warranty", "values": ["2 Year", "5 Year Premium Protection"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000084', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000003', 'Sony Smart Induction Hot Kettle', 'sony-smart-induction-kettle', 'High-frequency silent heat electric kettle with temperature app controls.', 'Maintains perfect baby formula or green tea temperature bounds using high precision thermal chips. Sleek insulated dual shell.', 'SONY-SMT-KTL', 95000.00, 85000.00, 10.53, 4.58, 76, 45, '[{"name": "Color", "values": ["Matte Black", "Chalk White"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000085', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000008', 'IKEA 365+ Stainless Steel Cookware (7-Piece)', 'ikea-365-cookware-set', 'Professional thick aluminum-core base steel pot set.', 'Features optimal heat distributions avoiding hot-spots. Works brilliantly on all stoves including induction. Glass lids.', 'IKEA-365-POT', 85000.00, 75000.00, 11.76, 4.72, 198, 60, '[{"name": "Bundle", "values": ["7-Piece Pots Set"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000086', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000008', 'IKEA VÖRDA Professional Chef Knife', 'ikea-vorda-chef-knife', 'Perfectly balanced molybdenum/vanadium steel kitchen knife.', 'Stays sharp for exceptional lifespans. Molded slip-resistant grooved synthetic rubber handle yields extremely safe grip lines.', 'IKEA-VRD-KNF', 18000.00, 15000.00, 16.67, 4.60, 312, 120, '[{"name": "Size", "values": ["20 cm Blade"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000087', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000002', 'Samsung NeoChefs Smart Microwave', 'samsung-neochef-microwave', '42L high power microwave oven with smart inverter tech.', 'Allows high-speed thawing, frying, and dynamic baking. Features antibacterial internal enamel lining blocks odors.', 'SAM-NEO-MW', 195000.00, 180000.00, 7.69, 4.65, 89, 30, '[{"name": "Color", "values": ["Reflective Black Glass", "Stainless Silver"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000088', 'c0000000-0000-0000-0000-000000000008', 'b0000000-0000-0000-0000-000000000008', 'IKEA BEKVÄM Solid Birch Spice Rack', 'ikea-bekvam-spice-rack', 'Solid natural wood spice shelf holder or book stand.', 'Completely natural birch panels. Easy painting styling or mountings directly on drywall or cabinets margins.', 'IKEA-BKV-SPC', 9500.00, 8000.00, 15.79, 4.54, 498, 200, '[{"name": "Bundle", "values": ["1x Wall Shelf", "3x Value Combo Pack"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000089', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000008', 'IKEA PROPPMÄTT Solid Beech Cutting Board', 'ikea-proppmatt-cutting-board', 'Large heavy organic beech wood chopping board.', 'A robust chopping panel gentle on knife blades. Double-sided use incorporating milled juice tracking groove margins.', 'IKEA-PRP-CTB', 14000.00, 12000.00, 14.29, 4.61, 234, 150, '[{"name": "Size", "values": ["38x27 cm", "45x36 cm Large"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000090', 'c0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000008', 'IKEA HÅLLBAR Pull-out Recycling Bin', 'ikea-hallbar-recycling-bin', 'Smart sliding kitchen cabinet recycling trash can.', 'Molded to fit standard kitchen under-sink shelves smoothly. Keeps odors locked inside double sealed lids.', 'IKEA-HLB-BIN', 22000.00, 18000.00, 18.18, 4.45, 114, 90, '[{"name": "Bundle", "values": ["Standard 20L Bin", "Double Sorting Combo Kit"]}]'::jsonb, 'active');
