('p0000000-0000-0000-0000-000000000097', 'c0000000-0000-0000-0000-000000000010', 'b0000000-0000-0000-0000-000000000009', 'Under Armour Latex Resistance Bands (3-Pack)', 'under-armour-resistance-bands', 'Premium heavy-duty latex fitness stretching loop bands.', 'Three distinct resistance levels (Light, Medium, Heavy) with inner non-rolling grip stripes. Includes mesh carrier bag.', 'UA-RST-BND', 18000.00, 15000.00, 16.67, 4.54, 214, 180, '[{"name": "Bundle", "values": ["3-Bands Bundle Set"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000098', 'c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'Apple Watch Nike Sports Band', 'apple-watch-nike-band', 'Dynamic, compression-molded perforated sports watch strap.', 'High-performance synthetic fluoroelastomer with breathability holes. Highly resistant, soft on skin, pin-and-tuck locks.', 'APL-NK-BAND', 65000.00, 59000.00, 9.23, 4.78, 142, 95, '[{"name": "Color", "values": ["Midnight/Sky Blue", "Starlight/Pink"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000099', 'c0000000-0000-0000-0000-000000000010', 'b0000000-0000-0000-0000-000000000004', 'Nike Premium Training Weight Gloves', 'nike-weight-gloves', 'Heavy-duty padded leather palm micro-ventilated workout gloves.', 'Ensures reliable bar friction and calluses protection. Integrated hook-and-loop adjustable elastic wrist wraps.', 'NIKE-WGT-GLV', 22000.00, 19000.00, 13.64, 4.48, 114, 120, '[{"name": "Size", "values": ["S", "M", "L", "XL"]}]'::jsonb, 'active'),
('p0000000-0000-0000-0000-000000000100', 'c0000000-0000-0000-0000-000000000010', 'b0000000-0000-0000-0000-000000000005', 'Adidas High-Speed Ball bearing Jump Rope', 'adidas-speed-jump-rope', 'Tangle-free steel cable speed skipping rope with foam grips.', 'Equipped with 360-degree high-frequency smooth rotation metal ball bearings. Easily adjustable steel cable length.', 'ADID-JMP-RPE', 14000.00, 12000.00, 14.29, 4.51, 312, 190, '[{"name": "Color", "values": ["Signal Green", "Base Black"]}]'::jsonb, 'active');
